scwin.f_FieldClear = function()  {
//    $c.gus.cfInitObjects(tb_retrieve,[lc_seaair,lc_ioClsCd,ed_etaFrom,ed_etaTo,ed_blno,ed_mblno,ed_cnd_ed_custCd,ed_cnd_txt_custNm,ed_consignee,txt_consignee,ed_notify,txt_notify,cnd_ed_dept,cnd_ed_deptnm]); // 조회조건의 테이블을 초기화. 
    $c.gus.cfInitObjects(tb_retrieve,null); // 조회조건의 테이블을 초기화. 
};
//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_PopUp = function (disGubun, chgGubun) {

    var rtnList = new Array();
    switch (disGubun) {
        case "Customer":
            udc_custCd.setSelectId('retrieveEngClntInfo')
            udc_custCd.ilCommonPopUp(scwin.udc_custCd_callBackFunc,
                ed_cnd_ed_custCd.getValue().trim(),     // 화면에서의 ??? Code Element의	Value                                  
                ed_cnd_txt_custNm.getValue(), 			// 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Customer search,Customer Code,Customer Name');

            break;
        case "Consignee":
            udc_consignee.setSelectId('retrieveEngClntInfo')
            udc_consignee.ilCommonPopUp(scwin.udc_consignee_callBackFunc,
                ed_consignee.getValue().trim(),        // 화면에서의 ??? Code Element의	Value                                  
                txt_consignee.getValue(),             // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Consignee Code,Consignee Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Consignee search,Consignee Code,Consignee Name');
                $c.gus.cfSetReturnValue(rtnList, ed_consignee,txt_consignee);
            break;
        case "Notify":
            udc_ntcd.setSelectId('retrieveEngClntInfo');
            udc_ntcd.ilCommonPopUp(scwin.callbackNotify ,
                ed_notify.getValue().trim(),        // 화면에서의 ??? Code Element의	Value                                  
                txt_notify.getValue(),             // 화면에서의 ??? Name Element의	Value                                  
                chgGubun,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '10',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Notify Code,Notify Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                '140,300,100,100,100,100,100,,,100',                      // 보여주는 각 컬럼들의 폭	                                               
                '8,9',                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                           // 윈도우 위치 Y좌표	                                                   
                null,                           // 윈도우 위치 X좌표                                                       
                null,                           // 중복체크여부	("F")                                                      
                "F",                            // 전체검색허용여부	("F")                                                  
                'Notify search,Notify Code,Notify Name');
                $c.gus.cfSetReturnValue(rtnList, ed_notify,txt_notify);
            break;
        case "DEPT" :           //retriveDepartmentCodeList
            udc_dept.setSelectId('retrieveEngClntInfo');
            udc_dept.ilCommonPopUp(scwin.udc_dept_callBackFunc
                                    ,cnd_ed_dept.getValue().trim()
                                    ,cnd_ed_deptnm.getValue()
                                    ,chgGubun
                                    ,'2'
                                    ,"Code, Name"
                                    ,'80,230'
                                    ,"3,4,5,6,7,8,9,10"
                                    ,null ,'500' ,'500' ,null ,null ,null
                                    ,"F"
                                    ,"DEPT,Code,Name"
                                    ); 
            break;  			  		            
    }

};
//---------------------------------------------------------
// 공통팝업 열기
