scwin.f_OpenCommonPopUp = function(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    var rtnList			= new Array();

    switch (gubun1) {		

        case "DEPT":
            udc_dept.setSelectId('retrieveOpDeptCdInfo')
            udc_dept.ilCommonPopUp(scwin.udc_dept_callBackFunc
                , cnd_ed_dept.getValue().trim()
                , cnd_ed_deptnm.getValue()
                , pWinCloseTF
                , '2'
                , "Code, Name"
                , '80,230'
                , "3,4,5,6,7,8,9,10"
                , null, null, null, null, null, null
                , pAllSearchTF
                , "DEPT,Code,Name"
                , pNoDataCloseTF
            );
            break;
    }	

}; 
